1	/**
2	 * Session Events Page
3	 *
4	 * This page displays detailed event information for a specific session and machine.
5	 * It acts as a lean wrapper around the SessionEventsPageContent component.
6	 *
7	 * @module app/sessions/[sessionId]/[machineId]/events/page
8	 */
9	
10	import { SessionsEventsPageContent } from '@/components/CMS/sessions/SessionsEventsPageContent';
11	import { use } from 'react';
12	
13	export default function SessionEventsPage({
14	  params,
15	}: {
16	  params: Promise<{ sessionId: string; machineId: string }>;
17	}) {
18	  const { sessionId, machineId } = use(params);
19	
20	  return (
21	    <SessionsEventsPageContent sessionId={sessionId} machineId={machineId} />
22	  );
23	}
