1	/**
2	 * Sessions API Route
3	 *
4	 * GET /api/sessions
5	 * Returns paginated machine session records with machine, location, licencee, and member details.
6	 * Supports search, date filtering, licencee filtering, sorting, and pagination.
7	 *
8	 * Flow:
9	 * 1. Parse query params
10	 * 2. Build match query (search + date filter)
11	 * 3. Build base pipeline with lookups and optional licencee filter
12	 * 4. Count total results
13	 * 5. Build full pipeline with member lookup, sort, pagination, and projection
14	 * 6. Return paginated results
15	 */
16	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
17	import {
18	  buildSessionBasePipeline,
19	  buildSessionFullPipeline,
20	  buildSessionMatchQuery,
21	} from '@/app/api/lib/helpers/sessions';
22	import { MachineSession } from '@/app/api/lib/models/machineSessions';
23	import {
24	  logRouteFetch,
25	  logRouteError,
26	  extractUserFromRequest,
27	} from '@/app/api/lib/utils/routeLogger';
28	import { NextRequest, NextResponse } from 'next/server';
29	
30	/**
31	 * GET /api/sessions
32	 * Fetches paginated session records with optional search, date, and licencee filters.
33	 *
34	 * @param {number} page - Page number (default: 1)
35	 * @param {number} limit - Items per page (default: 10)
36	 * @param {string} search - Search query for machine, location, or member
37	 * @param {string} sortBy - Field to sort by (default: 'startTime')
38	 * @param {string} sortOrder - 'asc' or 'desc' (default: 'desc')
39	 * @param {string} licencee - Filter by licencee ID
40	 * @param {string} dateFilter - Date range preset ('today', 'yesterday', '7d', '30d', 'all')
41	 * @param {string} startDate - ISO date for custom range start
42	 * @param {string} endDate - ISO date for custom range end
43	 */
44	export async function GET(request: NextRequest) {
45	  return withApiAuth(request, async () => {
46	    const startTime = Date.now();
47	    const functionName = 'GET /api/sessions';
48	    const user = extractUserFromRequest(request);
49	
50	    try {
51	      const { searchParams } = new URL(request.url);
52	      const page = parseInt(searchParams.get('page') || '1');
53	      const limit = parseInt(searchParams.get('limit') || '10');
54	      const search = searchParams.get('search') || '';
55	      const sortBy = searchParams.get('sortBy') || 'startTime';
56	      const sortOrder = searchParams.get('sortOrder') || 'desc';
57	      const licencee = searchParams.get('licencee') || '';
58	      const dateFilter = searchParams.get('dateFilter') || 'all';
59	      const startDateParam = searchParams.get('startDate');
60	      const endDateParam = searchParams.get('endDate');
61	
62	      // Step 1: Build match query from search and date params
63	      const matchQuery = buildSessionMatchQuery({
64	        search,
65	        dateFilter,
66	        startDateParam,
67	        endDateParam,
68	      });
69	
70	      // Step 2: Build base pipeline with lookups
71	      const basePipeline = buildSessionBasePipeline(matchQuery, licencee);
72	
73	      // Step 3: Count total matching documents
74	      const countResult = await MachineSession.aggregate([
75	        ...basePipeline,
76	        { $count: 'total' },
77	      ]);
78	      const totalSessions = countResult[0]?.total || 0;
79	
80	      // Step 4: Build full pipeline with member lookup, sort, pagination, projection
81	      const fullPipeline = buildSessionFullPipeline(basePipeline, {
82	        sortBy,
83	        sortOrder,
84	        page,
85	        limit,
86	        search,
87	      });
88	      const sessions = await MachineSession.aggregate(fullPipeline);
89	
90	      const duration = Date.now() - startTime;
91	      if (duration > 2000)
92	        console.warn(`[Sessions API] Completed in ${duration}ms`);
93	      logRouteFetch(
94	        functionName,
95	        'GET',
96	        '/api/sessions',
97	        sessions.length,
98	        user,
99	        duration
100	      );
101	
102	      return NextResponse.json({
103	        success: true,
104	        data: {
105	          sessions,
106	          pagination: {
107	            currentPage: page,
108	            totalPages: Math.ceil(totalSessions / limit),
109	            totalSessions,
110	            hasNextPage: page * limit < totalSessions,
111	            hasPrevPage: page > 1,
112	          },
113	        },
114	      });
115	    } catch (error) {
116	      const errorMessage =
117	        error instanceof Error ? error.message : 'Internal server error';
118	      logRouteError(functionName, 'GET', '/api/sessions', errorMessage, user);
119	      console.error(`[Sessions API] Error:`, error);
120	      return NextResponse.json(
121	        { success: false, error: 'Internal server error' },
122	        { status: 500 }
123	      );
124	    }
125	  });
126	}
