1	/**
2	 * Session Details API Route
3	 *
4	 * Fetches detailed information about a specific session, joining member profile
5	 * and machine data for display on the Session Details view.
6	 */
7	
8	import { connectDB } from '@/app/api/lib/middleware/db';
9	import { MachineSession } from '@/app/api/lib/models/machineSessions';
10	import {
11	  logRouteFetch,
12	  logRouteError,
13	  extractUserFromRequest,
14	} from '@/app/api/lib/utils/routeLogger';
15	import { NextRequest, NextResponse } from 'next/server';
16	
17	/**
18	 * GET /api/sessions/[sessionId]
19	 *
20	 * Fetches a single machine session with its joined member profile (firstName,
21	 * lastName) and machine record, plus the location's membership settings.
22	 * Used by the Session Details page to render the session header and metadata.
23	 *
24	 * URL params:
25	 * @param sessionId {string} Required (path). The string `_id` of the machine session to retrieve.
26	 */
27	export async function GET(request: NextRequest) {
28	  const startTime = Date.now();
29	  const functionName = 'GET /api/sessions/[sessionId]';
30	  const user = extractUserFromRequest(request);
31	  const { pathname } = request.nextUrl;
32	  const sessionId = pathname.split('/').pop();
33	
34	  try {
35	    await connectDB();
36	
37	    // Validate sessionId
38	    if (!sessionId || sessionId === 'undefined' || sessionId === 'null') {
39	      return NextResponse.json(
40	        { success: false, error: 'Invalid session ID' },
41	        { status: 400 }
42	      );
43	    }
44	
45	    // Since _id is defined as String in the schema, we match directly with the string sessionId
46	    const sessionDetails = await MachineSession.aggregate([
47	      { $match: { _id: sessionId } },
48	      {
49	        $lookup: {
50	          from: 'members',
51	          localField: 'memberId',
52	          foreignField: '_id',
53	          as: 'member',
54	        },
55	      },
56	      {
57	        $unwind: {
58	          path: '$member',
59	          preserveNullAndEmptyArrays: true,
60	        },
61	      },
62	      {
63	        $lookup: {
64	          from: 'machines',
65	          localField: 'machineId',
66	          foreignField: '_id',
67	          as: 'machine',
68	        },
69	      },
70	      {
71	        $unwind: {
72	          path: '$machine',
73	          preserveNullAndEmptyArrays: true,
74	        },
75	      },
76	      {
77	        $lookup: {
78	          from: 'gaminglocations',
79	          localField: 'machine.gamingLocation',
80	          foreignField: '_id',
81	          as: 'location',
82	        },
83	      },
84	      {
85	        $unwind: {
86	          path: '$location',
87	          preserveNullAndEmptyArrays: true,
88	        },
89	      },
90	      {
91	        $project: {
92	          _id: 1,
93	          memberId: 1,
94	          machineId: 1,
95	          startTime: 1,
96	          endTime: 1,
97	          status: 1,
98	          locationMembershipSettings: {
99	            $ifNull: [
100	              '$member.locationMembershipSettings',
101	              '$location.locationMembershipSettings',
102	            ],
103	          },
104	          memberFirstName: '$member.profile.firstName',
105	          memberLastName: '$member.profile.lastName',
106	        },
107	      },
108	    ]);
109	
110	    if (!sessionDetails || sessionDetails.length === 0) {
111	      return NextResponse.json(
112	        { success: false, error: 'Session not found' },
113	        { status: 404 }
114	      );
115	    }
116	
117	    const data = sessionDetails[0];
118	
119	    const duration = Date.now() - startTime;
120	    logRouteFetch(
121	      functionName,
122	      'GET',
123	      '/api/sessions/[sessionId]',
124	      1,
125	      user,
126	      duration
127	    );
128	
129	    return NextResponse.json({
130	      success: true,
131	      data,
132	    });
133	  } catch (error) {
134	    const duration = Date.now() - startTime;
135	    const errorMessage =
136	      error instanceof Error ? error.message : 'Internal server error';
137	    logRouteError(
138	      functionName,
139	      'GET',
140	      '/api/sessions/[sessionId]',
141	      errorMessage,
142	      user
143	    );
144	    console.error(
145	      `[SessionDetails API] Error after ${duration}ms:`,
146	      errorMessage
147	    );
148	
149	    return NextResponse.json(
150	      { success: false, error: errorMessage },
151	      { status: 500 }
152	    );
153	  }
154	}
