1	/**
2	 * Session Events API Route
3	 *
4	 * Fetches machine events scoped to a specific session and machine, with filtering,
5	 * time-range controls, pagination, and event-code cursor seek.
6	 *
7	 * Also returns unique filter values for eventType, description, and game dropdowns
8	 * in the same response so the UI can populate selects without extra requests.
9	 *
10	 * Flow:
11	 * 1. Parse path and query params
12	 * 2. Build the base match query (session + machine + active filters)
13	 * 3. Apply date range filtering
14	 * 4. If `command` param is provided, resolve the cursor page (seek to position)
15	 * 5. Run $facet aggregation: metadata count, paginated data, filter options
16	 * 6. Return events + pagination + filter options
17	 */
18	
19	import { connectDB } from '@/app/api/lib/middleware/db';
20	import { MachineEvent } from '@/app/api/lib/models/machineEvents';
21	import {
22	  logRouteFetch,
23	  logRouteError,
24	  extractUserFromRequest,
25	} from '@/app/api/lib/utils/routeLogger';
26	import { NextRequest, NextResponse } from 'next/server';
27	
28	/**
29	 * GET /api/sessions/[sessionId]/[machineId]/events
30	 *
31	 * Fetches paginated machine events filtered to a specific session and machine.
32	 * Supports narrowing by event category, log level, description text, game name,
33	 * date range (either an explicit window or a preset period), and event command code.
34	 *
35	 * URL params:
36	 * @param sessionId   {string} Required (path). The string `_id` of the session.
37	 * @param machineId   {string} Required (path). The string `_id` of the machine.
38	 *
39	 * Query params:
40	 * @param page        {number} Optional. 1-based page number (default: 1). Ignored when `command` is used for a cursor seek.
41	 * @param limit       {number} Optional. Number of events per page (default: 20).
42	 * @param timePeriod  {string} Optional. Preset: `Today`, `Yesterday`, `7d`, `30d`, `All Time`.
43	 * @param eventType   {string} Optional. Case-insensitive partial-match on `eventType` field.
44	 * @param type        {string} Optional. Case-insensitive match on `eventLogLevel` field.
45	 * @param event       {string} Optional. Case-insensitive partial-match on `description` field.
46	 * @param game        {string} Optional. Case-insensitive partial-match on `gameName`.
47	 * @param command     {string} Optional. Event code for cursor seek — resolves the page where the
48	 *                             first document with this command code appears and returns from that offset.
49	 * @param startDate   {string} Optional. ISO datetime for custom range start.
50	 * @param endDate     {string} Optional. ISO datetime for custom range end.
51	 */
52	export async function GET(request: NextRequest) {
53	  const startTime = Date.now();
54	  const functionName = 'GET /api/sessions/[sessionId]/[machineId]/events';
55	  const user = extractUserFromRequest(request);
56	  const { pathname } = request.nextUrl;
57	  const parts = pathname.split('/').filter(Boolean);
58	  const machineId = parts[parts.length - 2];
59	  const sessionId = parts[parts.length - 3];
60	
61	  try {
62	    // === STEP 1: Connect and parse params ===
63	    await connectDB();
64	
65	    const { searchParams } = new URL(request.url);
66	    const pageParam = parseInt(searchParams.get('page') || '1');
67	    const page = Number.isFinite(pageParam) && pageParam > 0 ? pageParam : 1;
68	
69	    const limitParam = parseInt(searchParams.get('limit') || '20');
70	    const limit =
71	      Number.isFinite(limitParam) && limitParam > 0
72	        ? Math.min(limitParam, 100)
73	        : 20;
74	
75	    const timePeriod = searchParams.get('timePeriod');
76	    const eventType = searchParams.get('eventType');
77	    const eventLogLevel = searchParams.get('type');
78	    const eventDescription = searchParams.get('event');
79	    const game = searchParams.get('game');
80	    const command = searchParams.get('command');
81	    const startDateParam = searchParams.get('startDate');
82	    const endDateParam = searchParams.get('endDate');
83	
84	    // === STEP 2: Build base match query ===
85	    // machine and currentSession are stored as Strings in this collection
86	    const matchQuery: Record<string, unknown> = {
87	      machine: machineId as string,
88	      currentSession: sessionId as string,
89	    };
90	
91	    if (eventType) {
92	      matchQuery.eventType = { $regex: eventType, $options: 'i' };
93	    }
94	
95	    if (eventLogLevel) {
96	      if (eventLogLevel.toLowerCase() === 'warning') {
97	        matchQuery.eventLogLevel = {
98	          $in: ['Warning', 'WARN', 'warning', 'warn'],
99	        };
100	      } else {
101	        matchQuery.eventLogLevel = { $regex: eventLogLevel, $options: 'i' };
102	      }
103	    }
104	
105	    if (eventDescription) {
106	      matchQuery.description = { $regex: eventDescription, $options: 'i' };
107	    }
108	
109	    if (game) {
110	      matchQuery.gameName = { $regex: game, $options: 'i' };
111	    }
112	
113	    // === STEP 3: Apply date range filtering ===
114	    if (startDateParam && endDateParam) {
115	      matchQuery.date = {
116	        $gte: new Date(startDateParam),
117	        $lte: new Date(endDateParam),
118	      };
119	    } else if (timePeriod && timePeriod !== 'All Time') {
120	      const tz = 'America/Port_of_Spain';
121	      const now = new Date();
122	      const formatter = new Intl.DateTimeFormat('en-CA', {
123	        timeZone: tz,
124	        year: 'numeric',
125	        month: 'numeric',
126	        day: 'numeric',
127	      });
128	      const parts = formatter.formatToParts(now);
129	      const year = parseInt(parts.find(p => p.type === 'year')!.value);
130	      const month = parseInt(parts.find(p => p.type === 'month')!.value) - 1;
131	      const day = parseInt(parts.find(p => p.type === 'day')!.value);
132	
133	      let dateStart: Date | null = null;
134	      let dateEnd: Date | null = null;
135	
136	      switch (timePeriod) {
137	        case 'Today':
138	          dateStart = new Date(Date.UTC(year, month, day, 4, 0, 0, 0));
139	          dateEnd = new Date(Date.UTC(year, month, day + 1, 3, 59, 59, 999));
140	          break;
141	        case 'Yesterday':
142	          dateStart = new Date(Date.UTC(year, month, day - 1, 4, 0, 0, 0));
143	          dateEnd = new Date(Date.UTC(year, month, day, 3, 59, 59, 999));
144	          break;
145	        case '7d':
146	        case 'last7days':
147	          dateEnd = now;
148	          dateStart = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
149	          break;
150	        case '30d':
151	        case 'last30days':
152	          dateEnd = now;
153	          dateStart = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
154	          break;
155	        default:
156	          break;
157	      }
158	
159	      if (dateStart && dateEnd) {
160	        matchQuery.date = { $gte: dateStart, $lte: dateEnd };
161	      }
162	    }
163	
164	    // === STEP 4: Resolve cursor page if command code is provided ===
165	    // Find the rank of the first document where command matches, then jump to that page.
166	    let resolvedPage = page;
167	    let cursorResolved = false;
168	
169	    if (command) {
170	      const commandMatchQuery = {
171	        ...matchQuery,
172	        command: { $regex: `^${command}$`, $options: 'i' },
173	      };
174	
175	      // Count how many documents appear before the first match (sorted by date desc)
176	      // We find the first document with this command, then count docs sorted before it.
177	      const firstMatch = await MachineEvent.findOne(commandMatchQuery)
178	        .sort({ date: -1 })
179	        .select('date _id')
180	        .lean<{ date: Date; _id: unknown }>();
181	
182	      if (firstMatch) {
183	        // Count documents that come before this one in the sorted result set
184	        const rankQuery: Record<string, unknown> = {
185	          ...matchQuery,
186	          date: { $gt: firstMatch.date },
187	        };
188	        const rankCount =
189	          await MachineEvent.countDocuments(rankQuery);
190	        resolvedPage = Math.floor(rankCount / limit) + 1;
191	        cursorResolved = true;
192	      }
193	    }
194	
195	    // === STEP 5: Run $facet aggregation ===
196	    const skip = (resolvedPage - 1) * limit;
197	
198	    const pipeline: import('mongoose').PipelineStage[] = [
199	      { $match: matchQuery },
200	      { $sort: { date: -1 } },
201	      {
202	        $facet: {
203	          data: [{ $skip: skip }, { $limit: limit }],
204	          eventTypes: [
205	            { $group: { _id: '$eventType' } },
206	            { $match: { _id: { $ne: null } } },
207	          ],
208	          eventLogLevels: [
209	            { $group: { _id: '$eventLogLevel' } },
210	            { $match: { _id: { $ne: null } } },
211	          ],
212	          descriptions: [
213	            { $group: { _id: '$description' } },
214	            { $match: { _id: { $ne: null } } },
215	            { $limit: 100 },
216	          ],
217	          games: [
218	            { $group: { _id: '$gameName' } },
219	            { $match: { _id: { $ne: null } } },
220	          ],
221	        },
222	      },
223	    ];
224	
225	    const result = await MachineEvent.aggregate(pipeline);
226	    const facetData = result[0];
227	    const events = facetData.data;
228	    // hasMore: if a full batch came back, more records exist on the server
229	    const hasMore = events.length === limit;
230	
231	    // === STEP 6: Return response ===
232	    const duration = Date.now() - startTime;
233	    logRouteFetch(
234	      functionName,
235	      'GET',
236	      '/api/sessions/[sessionId]/[machineId]/events',
237	      events.length,
238	      user,
239	      duration
240	    );
241	
242	    return NextResponse.json({
243	      success: true,
244	      data: {
245	        events,
246	        pagination: {
247	          currentPage: resolvedPage,
248	          hasMore,
249	          hasPrevPage: resolvedPage > 1,
250	          cursorResolved,
251	        },
252	        filters: {
253	          eventTypes: facetData.eventTypes
254	            .map((item: { _id: string }) => item._id)
255	            .filter(Boolean)
256	            .sort(),
257	          eventLogLevels: facetData.eventLogLevels
258	            .map((item: { _id: string }) => item._id)
259	            .filter(Boolean)
260	            .sort(),
261	          descriptions: facetData.descriptions
262	            .map((item: { _id: string }) => item._id)
263	            .filter(Boolean),
264	          games: facetData.games
265	            .map((item: { _id: string }) => item._id)
266	            .filter(Boolean)
267	            .sort(),
268	        },
269	      },
270	    });
271	  } catch (error: unknown) {
272	    const duration = Date.now() - startTime;
273	    const errorMessage =
274	      error instanceof Error ? error.message : 'Internal server error';
275	    logRouteError(
276	      functionName,
277	      'GET',
278	      '/api/sessions/[sessionId]/[machineId]/events',
279	      errorMessage,
280	      user
281	    );
282	    console.error(
283	      `[SessionEvents API] Error after ${duration}ms:`,
284	      errorMessage
285	    );
286	    return NextResponse.json(
287	      { success: false, error: errorMessage },
288	      { status: 500 }
289	    );
290	  }
291	}
