1	/**
2	 * Sessions Page Content Component
3	 *
4	 * Handles state and data fetching for the sessions overview page.
5	 *
6	 * @module components/sessions/SessionsPageContent
7	 */
8	
9	'use client';
10	
11	import PageLayout from '@/components/shared/layout/PageLayout';
12	import DateFilters from '@/components/shared/ui/common/DateFilters';
13	import { Input } from '@/components/shared/ui/input';
14	import PaginationControls from '@/components/shared/ui/PaginationControls';
15	import { IMAGES } from '@/lib/constants';
16	import { useSessions } from '@/lib/hooks/data/useSessions';
17	import { useDashBoardStore } from '@/lib/store/dashboardStore';
18	import { MagnifyingGlassIcon } from '@radix-ui/react-icons';
19	import { RefreshCw } from 'lucide-react';
20	import Image from 'next/image';
21	import { useState } from 'react';
22	import { SessionsTable } from './SessionsTable';
23	
24	export default function SessionsPageContent() {
25	  // ============================================================================
26	  // State & Hooks
27	  // ============================================================================
28	  // Use the useSessions hook which exposes data and filter controls
29	  const {
30	    sessions,
31	    loading: isLoading,
32	    // Filter props
33	    searchTerm,
34	    setSearchTerm,
35	    sortBy,
36	    setSortBy,
37	    sortOrder,
38	    setSortOrder,
39	    // Data operations
40	    currentPage,
41	    totalPages,
42	    pagination,
43	    handlePageChange,
44	    refreshSessions,
45	    // Status filter
46	    statusFilter,
47	    setStatusFilter,
48	    clearFilters,
49	    hasActiveFilters,
50	  } = useSessions();
51	
52	  // Dashboard store specific for Licencee
53	  const { selectedLicencee, setSelectedLicencee } = useDashBoardStore();
54	
55	  const [refreshing, setRefreshing] = useState(false);
56	
57	  // ============================================================================
58	  // Handlers
59	  // ============================================================================
60	  const handleRefresh = async () => {
61	    setRefreshing(true);
62	    if (refreshSessions) {
63	      await refreshSessions();
64	    }
65	    setRefreshing(false);
66	  };
67	
68	  const handleSort = (field: string) => {
69	    const newSortOrder =
70	      sortBy === field && sortOrder === 'asc' ? 'desc' : 'asc';
71	    setSortBy(field);
72	    setSortOrder(newSortOrder);
73	  };
74	
75	  // ============================================================================
76	  // Render
77	  // ============================================================================
78	  return (
79	    <PageLayout
80	      headerProps={{
81	        selectedLicencee,
82	        setSelectedLicencee,
83	        disabled: false,
84	      }}
