197	
198	  // ============================================================================
199	  // Computed — batch pagination
200	  // ============================================================================
201	
202	  // Slice of accumulated events for the current client page
203	  const paginatedEvents = useMemo(() => {
204	    const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
205	    return accumulatedEvents.slice(startIndex, startIndex + ITEMS_PER_PAGE);
206	  }, [accumulatedEvents, currentPage, ITEMS_PER_PAGE]);
207	
208	  // Show loaded client pages + 1 trigger page when the server has more records,
209	  // mirroring the useLocationsPageData pattern. No COUNT query needed.
210	  const effectiveTotalPages = useMemo(() => {
211	    const loadedPages = Math.ceil(accumulatedEvents.length / ITEMS_PER_PAGE) || 1;
212	    return hasMoreData ? loadedPages + 1 : loadedPages;
213	  }, [accumulatedEvents.length, hasMoreData, ITEMS_PER_PAGE]);
