26	export function formatDuration(minutes: number): string {
27	  if (!minutes || isNaN(minutes)) return '0:00:00';
28	  const totalSeconds = Math.floor(minutes * 60);
29	  const hours = Math.floor(totalSeconds / 3600);
30	  const mins = Math.floor((totalSeconds % 3600) / 60);
31	  const secs = totalSeconds % 60;
32	  return `${hours}:${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
33	}
