1	/**
2	 * @module app/api/sessions/[sessionId]/route
3	 *
4	 * Session Details API Route
5	 *
6	 * Fetches detailed information about a specific session, joining member profile
7	 * and machine data for display on the Session Details view.
8	 *
9	 * Flow:
10	 * 1. Validate sessionId path param
11	 * 2. Aggregate session with member, machine, and location lookups
12	 * 3. Return session details
13	 */
14	
15	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
16	import { MachineSession } from '@/app/api/lib/models/machineSessions';
17	import {
18	  logRouteFetch,
19	  logRouteError,
20	  extractUserFromRequest,
21	} from '@/app/api/lib/utils/routeLogger';
22	import { NextRequest, NextResponse } from 'next/server';
23	
24	/**
25	 * GET /api/sessions/[sessionId]
26	 *
27	 * Fetches a single machine session with its joined member profile (firstName,
28	 * lastName) and machine record, plus the location's membership settings.
29	 * Used by the Session Details page to render the session header and metadata.
30	 *
31	 * URL params:
32	 * @param sessionId {string} Required (path). The string `_id` of the machine session to retrieve.
33	 */
34	export async function GET(request: NextRequest) {
35	  return withApiAuth(request, async () => {
36	  const startTime = Date.now();
37	  const functionName = 'GET /api/sessions/[sessionId]';
38	  const user = extractUserFromRequest(request);
39	  const { pathname } = request.nextUrl;
40	  const sessionId = pathname.split('/').pop();
41	
42	  try {
43	
44	    // Validate sessionId
45	    if (!sessionId || sessionId === 'undefined' || sessionId === 'null') {
46	      return NextResponse.json(
47	        { success: false, error: 'Invalid session ID' },
48	        { status: 400 }
49	      );
50	    }
51	
52	    // Since _id is defined as String in the schema, we match directly with the string sessionId
53	    const sessionDetails = await MachineSession.aggregate([
54	      { $match: { _id: sessionId } },
55	      {
56	        $lookup: {
57	          from: 'members',
58	          localField: 'memberId',
59	          foreignField: '_id',
60	          as: 'member',
61	        },
62	      },
63	      {
64	        $unwind: {
65	          path: '$member',
66	          preserveNullAndEmptyArrays: true,
67	        },
68	      },
69	      {
70	        $lookup: {
71	          from: 'machines',
72	          localField: 'machineId',
73	          foreignField: '_id',
74	          as: 'machine',
75	        },
76	      },
77	      {
78	        $unwind: {
79	          path: '$machine',
80	          preserveNullAndEmptyArrays: true,
81	        },
82	      },
83	      {
84	        $lookup: {
85	          from: 'gaminglocations',
86	          localField: 'machine.gamingLocation',
87	          foreignField: '_id',
88	          as: 'location',
89	        },
90	      },
91	      {
92	        $unwind: {
93	          path: '$location',
94	          preserveNullAndEmptyArrays: true,
95	        },
96	      },
97	      {
98	        $project: {
99	          _id: 1,
100	          memberId: 1,
101	          machineId: 1,
102	          startTime: 1,
103	          endTime: 1,
104	          status: 1,
105	          locationMembershipSettings: {
106	            $ifNull: [
107	              '$member.locationMembershipSettings',
108	              '$location.locationMembershipSettings',
109	            ],
110	          },
111	          memberFirstName: '$member.profile.firstName',
112	          memberLastName: '$member.profile.lastName',
113	        },
114	      },
115	    ]);
116	
117	    if (!sessionDetails || sessionDetails.length === 0) {
118	      return NextResponse.json(
119	        { success: false, error: 'Session not found' },
120	        { status: 404 }
121	      );
122	    }
123	
124	    const data = sessionDetails[0];
125	
126	    const duration = Date.now() - startTime;
127	    if (duration > 1000) console.warn(`[${functionName}] slow: ${duration}ms`);
128	    logRouteFetch(
129	      functionName,
130	      'GET',
131	      '/api/sessions/[sessionId]',
132	      1,
133	      user,
134	      duration
135	    );
136	
137	    return NextResponse.json({
138	      success: true,
139	      data,
140	    });
141	  } catch (error) {
142	    const duration = Date.now() - startTime;
143	    const errorMessage =
144	      error instanceof Error ? error.message : 'Internal server error';
145	    logRouteError(
146	      functionName,
147	      'GET',
148	      '/api/sessions/[sessionId]',
149	      errorMessage,
150	      user
151	    );
152	    console.error(
153	      `[SessionDetails API] Error after ${duration}ms:`,
154	      errorMessage
155	    );
156	
157	    return NextResponse.json(
158	      { success: false, error: errorMessage },
159	      { status: 500 }
160	    );
161	  }
162	  });
163	}
