1	'use client';
2	
3	import { SessionsListSkeleton } from '@/components/shared/ui/skeletons/SessionsSkeletons';
4	import { SessionsTableProps } from '@/lib/types/sessions';
5	import { History } from 'lucide-react';
6	import { SessionsDesktopTable } from './SessionsDesktopTable';
7	import { SessionsMobileCards } from './SessionsMobileCards';
8	
9	/**
10	 * Main Sessions Table Component
11	 *
12	 * Renders either a desktop table or mobile cards based on screen size.
13	 * Handles loading and empty states.
14	 */
15	export function SessionsTable({
16	  sessions,
17	  isLoading,
18	  sortOption,
19	  sortOrder,
20	  onSort,
21	}: SessionsTableProps) {
22	  // ============================================================================
23	  // Render
24	  // ============================================================================
25	  // === Loading State ===
26	  if (isLoading) {
27	    return <SessionsListSkeleton />;
28	  }
29	
30	  // === Empty State ===
31	  if (!sessions || sessions.length === 0) {
32	    return (
33	      <div className="flex h-64 flex-col items-center justify-center rounded-lg border-2 border-dashed border-gray-200 bg-gray-50 p-12 text-center">
34	        <History className="mb-4 h-12 w-12 text-gray-300" />
35	        <h3 className="text-lg font-medium text-gray-900">No sessions found</h3>
36	        <p className="text-sm text-gray-500">
37	          Try adjusting your search or filters to find what you're looking for.
38	        </p>
39	      </div>
40	    );
41	  }
42	
43	  // === Render Components ===
44	  return (
45	    <>
46	      <SessionsDesktopTable
47	        sessions={sessions}
48	        sortOption={sortOption}
49	        sortOrder={sortOrder}
50	        onSort={onSort}
51	      />
52	      <SessionsMobileCards sessions={sessions} />
53	    </>
54	  );
55	}
